#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long ans = 0;
        for(int i=0;i<N;i++){
            long long a; scanf("%lld", &a);
            long long r = a % K;
            if(r==0) continue; // already multiple of K
            long long dec = r;
            if(a - r == 0) dec = (long long)9e18; // cannot make zero
            long long inc = K - r;
            ans += (dec < inc ? dec : inc);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

