#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); K = next(it)
        ans = 0
        for _ in range(N):
            a = next(it)
            r = a % K
            if r == 0:
                continue
            if a - r == 0:
                ans += K - r
            else:
                ans += min(r, K - r)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

